function score(e,n,t){const o=document.querySelector("[name=csrfmiddlewaretoken]").value;$.post({url:"/score",contentType:"application/json",headers:{"X-CSRFToken":o},data:JSON.stringify({answer:n,points:t}),success:n=>{"ok"===n&&($(e).siblings("button.points").removeClass("active"),$(e).addClass("active"))}})}$(document).ready(function(){$("a.button[disabled]").click(function(e){e.preventDefault()})});